const items = $input.all();

function normEmail(e) {
  if (!e || typeof e !== 'string') return null;
  return e.trim().toLowerCase();
}

function normDomain(d) {
  if (!d || typeof d !== 'string') return null;
  let v = d.trim().toLowerCase();
  v = v.replace(/^https?:\/\//, '').replace(/^www\./, '');
  v = v.split('/')[0].split('?')[0].split('#')[0];
  v = v.replace(/:\d+$/, '');
  return (v && v.includes('.')) ? v : null;
}

function isValidEmail(e) {
  return /^[a-z0-9._%+\-]+@[a-z0-9.\-]+\.[a-z]{2,}$/.test(e);
}

const results = [];

for (const item of items) {
  const r = item.json;
  const email = normEmail(r.email);
  const domain = normDomain(r.domain);
  const bizName = (r.business_name || '').trim();

  // Required field validation
  const missing = [];
  if (!email) missing.push('email');
  if (!domain) missing.push('domain');
  if (!isValidEmail(email || '')) missing.push('email_format');
  if (!r.id) missing.push('id');

  const valid = missing.length === 0;

  results.push({
    json: {
      id: r.id,
      business_name: bizName,
      website: r.website || null,
      domain: domain,
      email: email,
      email_status: r.email_status,
      lead_status: r.lead_status,
      outreach_status: r.outreach_status,
      export_status: r.export_status,
      smartlead_status: r.smartlead_status,
      needs_manual_review: r.needs_manual_review || false,
      created_at: r.created_at,
      updated_at: r.updated_at,
      _valid: valid,
      _missing_fields: missing,
      _norm_email: email,
      _norm_domain: domain,
      _norm_biz: bizName.toLowerCase().replace(/[^a-z0-9]/g, '')
    }
  });
}

return results;

const items = $input.all();

// --- Phase 1: Mark invalid rows as blocked ---
const valid = [];
const blocked = [];

for (const item of items) {
  const r = item.json;
  if (!r._valid) {
    blocked.push({
      ...r,
      export_decision: 'blocked',
      smartlead_decision: 'not_exportable',
      review_decision: true,
      decision_reason: 'missing_fields:' + (r._missing_fields || []).join(',')
    });
  } else {
    valid.push(r);
  }
}

// --- Phase 2: Email dedup ---
// Group by normalized email
const byEmail = new Map();
for (const r of valid) {
  const key = r._norm_email;
  if (!byEmail.has(key)) byEmail.set(key, []);
  byEmail.get(key).push(r);
}

function pickWinner(rows) {
  return rows.sort((a, b) => {
    // 1. verified beats risky
    const aV = a.email_status === 'verified' ? 1 : 0;
    const bV = b.email_status === 'verified' ? 1 : 0;
    if (bV !== aV) return bV - aV;

    // 2. has business_name beats missing
    const aB = a.business_name ? 1 : 0;
    const bB = b.business_name ? 1 : 0;
    if (bB !== aB) return bB - aB;

    // 3. older created_at wins
    const aT = new Date(a.created_at || 0).getTime();
    const bT = new Date(b.created_at || 0).getTime();
    return aT - bT;
  })[0];
}

const emailWinners = new Map();
const emailDupes = [];

for (const [email, rows] of byEmail) {
  if (rows.length === 1) {
    emailWinners.set(rows[0].id, rows[0]);
  } else {
    const winner = pickWinner([...rows]);
    emailWinners.set(winner.id, winner);
    for (const r of rows) {
      if (r.id !== winner.id) {
        emailDupes.push({
          ...r,
          export_decision: 'duplicate',
          smartlead_decision: 'not_exportable',
          review_decision: true,
          decision_reason: 'email_duplicate_of:' + winner.id
        });
      }
    }
  }
}

// --- Phase 3: Domain dedup (obvious duplicates only) ---
// Group email-winners by domain
const byDomain = new Map();
for (const [id, r] of emailWinners) {
  const key = r._norm_domain;
  if (!byDomain.has(key)) byDomain.set(key, []);
  byDomain.get(key).push(r);
}

function isSimilarBiz(a, b) {
  if (!a || !b) return false;
  if (a === b) return true;
  // One contains the other
  if (a.includes(b) || b.includes(a)) return true;
  // Levenshtein-ish: >70% character overlap
  const longer = a.length > b.length ? a : b;
  const shorter = a.length > b.length ? b : a;
  if (shorter.length < 3) return false;
  let matches = 0;
  for (let i = 0; i < shorter.length; i++) {
    if (longer.includes(shorter[i])) matches++;
  }
  return (matches / longer.length) > 0.7;
}

const domainDupes = [];
const winners = new Map();

for (const [domain, rows] of byDomain) {
  if (rows.length === 1) {
    winners.set(rows[0].id, rows[0]);
    continue;
  }

  // Check for obvious duplicates (same/similar biz name)
  const groups = [];
  const assigned = new Set();

  for (let i = 0; i < rows.length; i++) {
    if (assigned.has(i)) continue;
    const group = [rows[i]];
    assigned.add(i);
    for (let j = i + 1; j < rows.length; j++) {
      if (assigned.has(j)) continue;
      if (isSimilarBiz(rows[i]._norm_biz, rows[j]._norm_biz)) {
        group.push(rows[j]);
        assigned.add(j);
      }
    }
    groups.push(group);
  }

  for (const group of groups) {
    if (group.length === 1) {
      winners.set(group[0].id, group[0]);
    } else {
      const winner = pickWinner([...group]);
      winners.set(winner.id, winner);
      for (const r of group) {
        if (r.id !== winner.id) {
          domainDupes.push({
            ...r,
            export_decision: 'duplicate',
            smartlead_decision: 'not_exportable',
            review_decision: true,
            decision_reason: 'domain_duplicate_of:' + winner.id
          });
        }
      }
    }
  }
}

// --- Phase 4: Assign ready status to winners ---
const ready = [];
for (const [id, r] of winners) {
  const isRisky = r.email_status === 'risky';
  ready.push({
    ...r,
    export_decision: 'ready',
    smartlead_decision: 'pending_export',
    review_decision: isRisky ? true : r.needs_manual_review,
    decision_reason: isRisky ? 'risky_email' : 'clean'
  });
}

// --- Combine all ---
const all = [...ready, ...blocked, ...emailDupes, ...domainDupes];

return all.map(r => ({ json: r }));

// Collect all processed decisions and build ready-for-export output
const items = $('Code - Resolve Duplicates and Decide').all();

const ready = [];
let totalProcessed = 0;
let readyCount = 0;
let blockedCount = 0;
let duplicateCount = 0;
let riskyCount = 0;

for (const item of items) {
  const r = item.json;
  totalProcessed++;

  if (r.export_decision === 'ready') {
    readyCount++;
    if (r.email_status === 'risky') riskyCount++;
    ready.push({
      id: r.id,
      business_name: r.business_name,
      email: r._norm_email || r.email,
      domain: r._norm_domain || r.domain,
      website: r.website,
      email_status: r.email_status,
      lead_status: r.lead_status,
      export_status: 'ready',
      smartlead_status: 'pending_export'
    });
  } else if (r.export_decision === 'blocked') {
    blockedCount++;
  } else if (r.export_decision === 'duplicate') {
    duplicateCount++;
  }
}

// First item is the summary, rest are ready rows
const output = [{
  json: {
    _type: 'summary',
    total_processed: totalProcessed,
    ready_for_export: readyCount,
    risky: riskyCount,
    blocked: blockedCount,
    duplicates: duplicateCount
  }
}];

for (const row of ready) {
  output.push({ json: { _type: 'export_row', ...row } });
}

return output;
